Here are comprehensive pytest-style unit tests for the `zip_dicts` function:

```python
import pytest
from solution import zip_dicts


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestZipDictsHappyPath:

    def test_two_dicts_with_identical_keys(self):
        result = zip_dicts({"a": 1, "b": 2}, {"a": 3, "b": 4})
        assert result == {"a": [1, 3], "b": [2, 4]}

    def test_three_dicts_with_identical_keys(self):
        result = zip_dicts({"x": 1}, {"x": 2}, {"x": 3})
        assert result == {"x": [1, 2, 3]}

    def test_two_dicts_with_disjoint_keys(self):
        result = zip_dicts({"a": 1}, {"b": 2})
        assert result == {"a": [1, None], "b": [None, 2]}

    def test_two_dicts_with_overlapping_keys(self):
        result = zip_dicts({"a": 1, "b": 2}, {"b": 3, "c": 4})
        assert result == {"a": [1, None], "b": [2, 3], "c": [None, 4]}

    def test_single_dict(self):
        result = zip_dicts({"a": 1, "b": 2})
        assert result == {"a": [1], "b": [2]}

    def test_values_of_various_types(self):
        result = zip_dicts(
            {"a": 1, "b": "hello", "c": [1, 2]},
            {"a": 2.5, "b": True, "c": None},
        )
        assert result == {
            "a": [1, 2.5],
            "b": ["hello", True],
            "c": [[1, 2], None],
        }

    def test_integer_keys(self):
        result = zip_dicts({1: "a", 2: "b"}, {1: "c", 3: "d"})
        assert result == {1: ["a", "c"], 2: ["b", None], 3: [None, "d"]}

    def test_many_dicts(self):
        dicts = [{"key": i} for i in range(10)]
        result = zip_dicts(*dicts)
        assert result == {"key": list(range(10))}

    def test_preserves_all_values_including_falsy(self):
        result = zip_dicts({"a": 0, "b": False, "c": ""}, {"a": 1, "b": True, "c": "x"})
        assert result == {"a": [0, 1], "b": [False, True], "c": ["", "x"]}


# ---------------------------------------------------------------------------
# Edge case tests
# ---------------------------------------------------------------------------

class TestZipDictsEdgeCases:

    def test_no_arguments_returns_empty_dict(self):
        result = zip_dicts()
        assert result == {}

    def test_single_empty_dict(self):
        result = zip_dicts({})
        assert result == {}

    def test_two_empty_dicts(self):
        result = zip_dicts({}, {})
        assert result == {}

    def test_one_empty_one_non_empty(self):
        result = zip_dicts({}, {"a": 1, "b": 2})
        assert result == {"a": [None, 1], "b": [None, 2]}

    def test_value_is_none_vs_missing_key(self):
        """A value explicitly set to None should be distinguishable from a
        missing key only by position, since both produce None in the list."""
        result = zip_dicts({"a": None}, {"b": 1})
        assert result["a"] == [None, None]  # first
